{"command": "python3 << 'EOF'
with open('train.py', 'r') as f:
    lines = f.readlines()

# Find and fix the formatting of hyperparameter lines
for i, line in enumerate(lines):
    if line.startswith('EMBEDDING_LR'):
        lines[i] = 'EMBEDDING_LR = 0.77      # learning rate for token embeddings (Adam)\n'
    elif line.startswith('UNEMBEDDING_LR'):
        lines[i] = 'UNEMBEDDING_LR = 0.0052  # learning rate for lm_head (Adam)\n'
    elif line.startswith('MATRIX_LR'):
        lines[i] = 'MATRIX_LR = 0.050        # learning rate for matrix parameters (Muon)\n'
    elif line.startswith('SCALAR_LR'):
        lines[i] = 'SCALAR_LR = 0.52         # learning rate for per-layer scalars (Adam)\n'
    elif line.startswith('WEIGHT_DECAY'):
        lines[i] = 'WEIGHT_DECAY = 0.18      # cautious weight decay for Muon\n'
    elif line.startswith('WARMDOWN_RATIO'):
        lines[i] = 'WARMDOWN_RATIO = 0.32    # fraction of time budget for LR warmdown\n'
    elif line.startswith('FINAL_LR_FRAC'):
        lines[i] = 'FINAL_LR_FRAC = 0.06     # final LR as fraction of initial\n'
    elif line.startswith('DEPTH = '):
        lines[i] = 'DEPTH = 9               # number of transformer layers\n'
    elif line.startswith('DEVICE_BATCH_SIZE = '):
        lines[i] = 'DEVICE_BATCH_SIZE = 64  # per-device batch size (reduce if OOM)\n'

with open('train.py', 'w') as f:
    f.writelines(lines)

print("Formatting cleaned up")
EOF
"}

